#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    ll n;    cin>>n;    for(int i=1; i<=n; i++){        // i nested pairs at begining        for(int j=1; j<=i; j++){            cout<<'(';        }        for(int j=1; j<=i; j++){            cout<<')';        }        // then (n-i) separate pairs        for(int j=1; j<=n-i; j++){            cout<<"()";        }        cout<<nl;    }} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}     /*First i pairs are nested "((...))" & remaining n-i pairs are separate "()()...()".*/